// app/api/ask/route.ts - PHASE 2 DEEPSEEK + PDF PARSING
import { NextResponse } from 'next/server';
import pdf from 'pdf-parse';
import axios from 'axios';
import { getDownloadURL, getStorage, ref } from 'firebase/storage';
import { initializeApp } from 'firebase/app';

const firebaseConfig = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY!,
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN!,
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID!,
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET!,
};

const app = initializeApp(firebaseConfig);
const storage = getStorage(app);

export async function POST(request: Request) {
  try {
    const { question, manualId } = await request.json();
    
    // 1. Get PDF URL from Firebase
    const pdfRef = ref(storage, `manuals/${manualId}`);
    const pdfUrl = await getDownloadURL(pdfRef);
    
    // 2. Download & parse PDF
    const pdfResponse = await axios.get(pdfUrl, { responseType: 'arraybuffer' });
    const pdfData = await pdf(pdfResponse.data);
    const pdfText = pdfData.text.slice(0, 4000); // First 4K chars (DeepSeek limit)
    
    // 3. DeepSeek API call
    const deepseekResponse = await axios.post('https://api.deepseek.com/v1/chat/completions', {
      model: 'deepseek-r1',
      messages: [{
        role: 'user',
        content: `CAR MANUAL: "${pdfText.substring(0, 3000)}"
        
        Question: ${question}
        Answer using ONLY the manual text above. Include page numbers if found. Be precise.`
      }],
      max_tokens: 500,
      temperature: 0.1
    }, {
      headers: {
        'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
        'Content-Type': 'application/json'
      }
    });
    
    const answer = deepseekResponse.data.choices[0].message.content;
    
    return NextResponse.json({
      success: true,
      answer,
      manualId,
      sources: [`${manualId} (${pdfData.numpages} pages)`]
    });
    
  } catch (error: any) {
    console.error('Phase 2 error:', error.message);
    return NextResponse.json({ 
      error: 'DeepSeek processing failed - using backup responses',
      answer: 'Consult your manual for specific maintenance schedules.'
    }, { status: 500 });
  }
}

